<template>
    <div style="width: 40%; margin-left: 200px">
        <div style="margin-bottom: 50px; margin-left: 280px" >编辑用户</div>
        <el-form :model="ruleForm" :rules="rules" ref="ruleForm" label-width="200px">
            <el-form-item label="姓名" prop="name">
                <el-input v-model="ruleForm.name" placeholder="请输入姓名" disabled="true"></el-input>
            </el-form-item>
            <el-form-item label="用户名" prop="username" >
                <el-input v-model="ruleForm.username" placeholder="请输入用户名" disabled="true"></el-input>
            </el-form-item>
            <el-form-item label="年龄" prop="age">
                <el-input v-model="ruleForm.age" placeholder="请输入年龄"></el-input>
            </el-form-item>
            <el-form-item label="性别">
                <el-radio  v-model="ruleForm.sex" label="男">男</el-radio>
                <el-radio  v-model="ruleForm.sex" label="女">女</el-radio>
            </el-form-item>
            <el-form-item label="联系方式" prop="phone">
                <el-input v-model="ruleForm.phone" placeholder="请输入联系方式"></el-input>
            </el-form-item>
        </el-form>
        <div style="margin-left: 290px; margin-top: 40px">
            <el-button type="primary" @click="save">提交</el-button>
        </div>
    </div>
</template>

<script>
    import request from "@/utils/request";
    //导入请求
    export default {
        name: "EditUser",
        data(){

            return {
                ruleForm: {

                },
            }

        },
        created() {
            const id = this.$route.query.id
            request.get("/user/" + id).then(res =>{
                this.ruleForm = res.data
                //form改为ruleForm
            })
        },
        methods: {
            save() {
                request.put('/user/update',this.ruleForm).then(res =>{
                    if(res.code === '200'){
                        this.$notify.success('更新成功')
                        this.$router.push("/userList")
                    }else{
                        this.$notify.error(res.msg)
                    }
                })
                //    对接的是后台的UserController.java文件的路径
            }
        }
    }
</script>

